exercises.solution:
function sumAll(...numbers) {
  return numbers.reduce((acc, n) => acc + n, 0);
}

function sumWithMin(minimum, ...numbers) {
  return numbers
    .filter(n => n >= minimum)
    .reduce((acc, n) => acc + n, 0);
}

console.log(sumAll(1, 2, 3, 4, 5));
console.log(sumAll(10, 20));
console.log(sumWithMin(5, 1, 3, 5, 7, 10, 2));
console.log(sumWithMin(10, 5, 10, 15, 3, 20));
